    'CodeBlock.vue':
      '<script setup lang="ts">\nimport type { CodeBlockProps } from \'./code-block.types\'\nimport { computed, provide } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<CodeBlockProps>(), {\n  showLineNumbers: true,\n})\n\nprovide(\'code-block-code\', computed(() => props.code))\nprovide(\'code-block-language\', computed(() => props.language))\nprovide(\'code-block-showLineNumbers\', computed(() => props.showLineNumbers))\n\nconst classes = computed(() =>\n  cn(\n    \'overflow-hidden rounded-lg border bg-zinc-950 text-zinc-50\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <div :class="classes">\n    <slot />\n  </div>\n</template>\n',
    'CodeBlockContent.vue':
      '<script setup lang="ts">\nimport type { CodeBlockContentProps } from \'./code-block.types\'\nimport { computed, inject, ref, type Ref } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<CodeBlockContentProps>(), {\n  code: \'\',\n  showLineNumbers: undefined,\n})\n\nconst injectedCode = inject<Ref<string>>(\'code-block-code\', ref(\'\'))\nconst injectedShowLineNumbers = inject<Ref<boolean>>(\'code-block-showLineNumbers\', ref(true))\n\nconst displayCode = computed(() => props.code || injectedCode?.value || \'\')\nconst showLines = computed(() => props.showLineNumbers ?? injectedShowLineNumbers?.value ?? true)\n\nconst lines = computed(() => displayCode.value.split(\'\\n\'))\n\nconst classes = computed(() =>\n  cn(\'overflow-x-auto p-4\', props.class),\n)\n</script>\n\n<template>\n  <div :class="classes">\n    <pre class="text-sm leading-relaxed"><code><table class="w-full border-collapse"><tbody><tr\n      v-for="(line, index) in lines"\n      :key="index"\n    ><td\n      v-if="showLines"\n      class="select-none pr-4 text-right text-zinc-500"\n      :style="{ minWidth: `${String(lines.length).length + 1}ch` }"\n    >{{ index + 1 }}</td><td class="whitespace-pre">{{ line }}</td></tr></tbody></table></code></pre>\n  </div>\n</template>\n',
    'CodeBlockHeader.vue':
      '<script setup lang="ts">\nimport type { CodeBlockHeaderProps } from \'./code-block.types\'\nimport { computed, inject, ref, type Ref } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = defineProps<CodeBlockHeaderProps>()\n\nconst injectedLanguage = inject<Ref<string | undefined>>(\'code-block-language\', ref(undefined))\nconst injectedCode = inject<Ref<string>>(\'code-block-code\', ref(\'\'))\n\nconst displayLanguage = computed(() => props.language ?? injectedLanguage?.value)\nconst codeToCopy = computed(() => props.code ?? injectedCode?.value ?? \'\')\n\nconst copied = ref(false)\n\nasync function handleCopy() {\n  try {\n    await navigator.clipboard.writeText(codeToCopy.value)\n    copied.value = true\n    setTimeout(() => {\n      copied.value = false\n    }, 2000)\n  }\n  catch {\n    // Clipboard API not available\n  }\n}\n\nconst classes = computed(() =>\n  cn(\n    \'flex items-center justify-between border-b border-zinc-800 px-4 py-2\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <div :class="classes">\n    <span v-if="displayLanguage" class="text-xs text-zinc-400">{{ displayLanguage }}</span>\n    <span v-else />\n    <button\n      class="inline-flex items-center gap-1.5 rounded-md px-2 py-1 text-xs text-zinc-400 transition-colors hover:bg-zinc-800 hover:text-zinc-200"\n      aria-label="Copy code"\n      @click="handleCopy"\n    >\n      <svg\n        v-if="!copied"\n        xmlns="http://www.w3.org/2000/svg"\n        width="14"\n        height="14"\n        viewBox="0 0 24 24"\n        fill="none"\n        stroke="currentColor"\n        stroke-width="2"\n        stroke-linecap="round"\n        stroke-linejoin="round"\n      >\n        <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />\n        <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />\n      </svg>\n      <svg\n        v-else\n        xmlns="http://www.w3.org/2000/svg"\n        width="14"\n        height="14"\n        viewBox="0 0 24 24"\n        fill="none"\n        stroke="currentColor"\n        stroke-width="2"\n        stroke-linecap="round"\n        stroke-linejoin="round"\n      >\n        <polyline points="20 6 9 17 4 12" />\n      </svg>\n      {{ copied ? \'Copied\' : \'Copy\' }}\n    </button>\n  </div>\n</template>\n',
    'code-block.types.ts':
      'import type { HTMLAttributes } from \'vue\'\n\nexport interface CodeBlockProps {\n  /** The code content to display */\n  code: string\n\n  /** The programming language */\n  language?: string\n\n  /**\n   * Show line numbers\n   * @default true\n   */\n  showLineNumbers?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface CodeBlockHeaderProps {\n  /** The programming language label */\n  language?: string\n\n  /** The code to copy */\n  code?: string\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface CodeBlockContentProps {\n  /** The code content to display (optional, falls back to parent CodeBlock\'s code) */\n  code?: string\n\n  /**\n   * Show line numbers\n   * @default true\n   */\n  showLineNumbers?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n',
