    'ComboboxTrigger.vue':
      '<script setup lang="ts">\nimport type { ComboboxTriggerProps } from \'./combobox.types\'\nimport { ComboboxTrigger as ComboboxTriggerPrimitive } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = defineProps<ComboboxTriggerProps>()\n\nconst classes = computed(() =>\n  cn(\n    \'inline-flex items-center justify-center shrink-0\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <ComboboxTriggerPrimitive :class="classes">\n    <slot>\n      <svg\n        xmlns="http://www.w3.org/2000/svg"\n        width="16"\n        height="16"\n        viewBox="0 0 24 24"\n        fill="none"\n        stroke="currentColor"\n        stroke-width="2"\n        stroke-linecap="round"\n        stroke-linejoin="round"\n        class="h-4 w-4 shrink-0 opacity-50"\n        aria-hidden="true"\n      >\n        <polyline points="6 9 12 15 18 9" />\n      </svg>\n    </slot>\n  </ComboboxTriggerPrimitive>\n</template>\n',
    'combobox.types.ts':
      'import type { HTMLAttributes } from \'vue\'\n\nexport interface ComboboxProps {\n  /**\n   * The controlled value of the Combobox. Can be bound as `v-model`.\n   * @default undefined\n   */\n  modelValue?: string\n\n  /**\n   * The controlled open state of the Combobox. Can be bound as `v-model:open`.\n   * @default undefined\n   */\n  open?: boolean\n\n  /**\n   * The open state of the Combobox when it is initially rendered.\n   * @default false\n   */\n  defaultOpen?: boolean\n\n  /**\n   * Whether the Combobox is disabled.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** The name of the Combobox. Submitted with its owning form as part of a name/value pair. */\n  name?: string\n}\n\nexport interface ComboboxInputProps {\n  /** Placeholder text when no search term is entered */\n  placeholder?: string\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ComboboxTriggerProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ComboboxContentProps {\n  /**\n   * The positioning mode of the combobox content.\n   * @default \'popper\'\n   */\n  position?: \'inline\' | \'popper\'\n\n  /**\n   * The preferred side of the trigger to render against.\n   * @default \'bottom\'\n   */\n  side?: \'top\' | \'right\' | \'bottom\' | \'left\'\n\n  /**\n   * The distance in pixels from the trigger.\n   * @default 4\n   */\n  sideOffset?: number\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ComboboxItemProps {\n  /** The value of the item. Required. */\n  value: string\n\n  /**\n   * Whether the item is disabled.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ComboboxEmptyProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ComboboxGroupProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ComboboxLabelProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n',
    'index.ts':
      'export type {\n  ComboboxContentProps,\n  ComboboxEmptyProps,\n  ComboboxGroupProps,\n  ComboboxInputProps,\n  ComboboxItemProps,\n  ComboboxLabelProps,\n  ComboboxProps,\n  ComboboxTriggerProps,\n} from \'./combobox.types\'\nexport { default as Combobox } from \'./Combobox.vue\'\nexport { default as ComboboxContent } from \'./ComboboxContent.vue\'\nexport { default as ComboboxEmpty } from \'./ComboboxEmpty.vue\'\nexport { default as ComboboxGroup } from \'./ComboboxGroup.vue\'\nexport { default as ComboboxInput } from \'./ComboboxInput.vue\'\nexport { default as ComboboxItem } from \'./ComboboxItem.vue\'\nexport { default as ComboboxLabel } from \'./ComboboxLabel.vue\'\nexport { default as ComboboxTrigger } from \'./ComboboxTrigger.vue\'\n',
