      '<script setup lang="ts">\nimport type { MenubarSubTriggerProps } from \'./menubar.types\'\nimport { MenubarSubTrigger as MenubarSubTriggerPrimitive } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<MenubarSubTriggerProps>(), {\n  inset: false,\n  disabled: false,\n})\n\nconst classes = computed(() =>\n  cn(\n    \'flex h-8 cursor-default select-none items-center rounded-sm px-3 text-sm outline-none focus:bg-primary/10 focus:text-primary data-[state=open]:bg-primary/10\',\n    props.inset && \'pl-8\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <MenubarSubTriggerPrimitive :disabled="disabled" :class="classes">\n    <slot />\n    <svg\n      xmlns="http://www.w3.org/2000/svg"\n      width="16"\n      height="16"\n      viewBox="0 0 24 24"\n      fill="none"\n      stroke="currentColor"\n      stroke-width="2"\n      stroke-linecap="round"\n      stroke-linejoin="round"\n      class="ml-auto h-4 w-4"\n      aria-hidden="true"\n    >\n      <polyline points="9 18 15 12 9 6" />\n    </svg>\n  </MenubarSubTriggerPrimitive>\n</template>\n',
