    'index.ts':
      'export type {\n  MenubarCheckboxItemProps,\n  MenubarContentProps,\n  MenubarGroupProps,\n  MenubarItemProps,\n  MenubarLabelProps,\n  MenubarMenuProps,\n  MenubarProps,\n  MenubarRadioGroupProps,\n  MenubarRadioItemProps,\n  MenubarSeparatorProps,\n  MenubarShortcutProps,\n  MenubarSubContentProps,\n  MenubarSubProps,\n  MenubarSubTriggerProps,\n  MenubarTriggerProps,\n} from \'./menubar.types\'\nexport { default as Menubar } from \'./Menubar.vue\'\nexport { default as MenubarCheckboxItem } from \'./MenubarCheckboxItem.vue\'\nexport { default as MenubarContent } from \'./MenubarContent.vue\'\nexport { default as MenubarGroup } from \'./MenubarGroup.vue\'\nexport { default as MenubarItem } from \'./MenubarItem.vue\'\nexport { default as MenubarLabel } from \'./MenubarLabel.vue\'\nexport { default as MenubarMenu } from \'./MenubarMenu.vue\'\nexport { default as MenubarRadioGroup } from \'./MenubarRadioGroup.vue\'\nexport { default as MenubarRadioItem } from \'./MenubarRadioItem.vue\'\nexport { default as MenubarSeparator } from \'./MenubarSeparator.vue\'\nexport { default as MenubarShortcut } from \'./MenubarShortcut.vue\'\nexport { default as MenubarSub } from \'./MenubarSub.vue\'\nexport { default as MenubarSubContent } from \'./MenubarSubContent.vue\'\nexport { default as MenubarSubTrigger } from \'./MenubarSubTrigger.vue\'\nexport { default as MenubarTrigger } from \'./MenubarTrigger.vue\'\n',
    'menubar.types.ts':
      'import type { HTMLAttributes } from \'vue\'\n\nexport interface MenubarProps {\n  /**\n   * The controlled value of the menu to open. Used to force-open a specific menu by its value.\n   * @default undefined\n   */\n  modelValue?: string\n\n  /**\n   * The value of the menu that should be open when initially rendered.\n   * @default undefined\n   */\n  defaultValue?: string\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarMenuProps {\n  /**\n   * The value of the menu (for controlled open state).\n   * @default undefined\n   */\n  value?: string\n}\n\nexport interface MenubarTriggerProps {\n  /**\n   * When true, prevents the user from interacting with the trigger.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarContentProps {\n  /**\n   * The preferred alignment against the trigger.\n   * @default \'start\'\n   */\n  align?: \'start\' | \'center\' | \'end\'\n\n  /**\n   * The distance in pixels from the trigger.\n   * @default 8\n   */\n  sideOffset?: number\n\n  /**\n   * Alignment offset in pixels.\n   * @default -4\n   */\n  alignOffset?: number\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarItemProps {\n  /**\n   * When true, adds left padding to align with items that have an indicator.\n   * @default false\n   */\n  inset?: boolean\n\n  /**\n   * When true, prevents the user from interacting with the item.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarCheckboxItemProps {\n  /**\n   * The controlled checked state of the checkbox item.\n   * @default false\n   */\n  checked?: boolean\n\n  /**\n   * When true, prevents the user from interacting with the item.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarRadioGroupProps {\n  /**\n   * The controlled value of the radio group. Can be bound as `v-model`.\n   * @default undefined\n   */\n  modelValue?: string\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarRadioItemProps {\n  /** The value of the radio item. Required. */\n  value: string\n\n  /**\n   * When true, prevents the user from interacting with the item.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarLabelProps {\n  /**\n   * When true, adds left padding to align with items that have an indicator.\n   * @default false\n   */\n  inset?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarSeparatorProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarShortcutProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarGroupProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarSubProps {\n  /**\n   * The controlled open state of the submenu.\n   * @default undefined\n   */\n  open?: boolean\n\n  /**\n   * The open state of the submenu when it is initially rendered.\n   * @default false\n   */\n  defaultOpen?: boolean\n}\n\nexport interface MenubarSubTriggerProps {\n  /**\n   * When true, adds left padding to align with items that have an indicator.\n   * @default false\n   */\n  inset?: boolean\n\n  /**\n   * When true, prevents the user from interacting with the sub trigger.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface MenubarSubContentProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n',
