      '<script setup lang="ts">\nimport type { NavigationMenuListProps } from \'./navigation-menu.types\'\nimport { NavigationMenuList as NavigationMenuListPrimitive } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<NavigationMenuListProps>(), {})\n\nconst classes = computed(() =>\n  cn(\n    \'flex flex-1 list-none items-center justify-center space-x-1\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <NavigationMenuListPrimitive :class="classes">\n    <slot />\n  </NavigationMenuListPrimitive>\n</template>\n',
    'NavigationMenuTrigger.vue':
      '<script setup lang="ts">\nimport type { NavigationMenuTriggerProps } from \'./navigation-menu.types\'\nimport { NavigationMenuTrigger as NavigationMenuTriggerPrimitive } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<NavigationMenuTriggerProps>(), {\n  disabled: false,\n})\n\nconst classes = computed(() =>\n  cn(\n    \'group inline-flex h-10 w-max items-center justify-center rounded-md bg-background px-4 py-2 text-sm font-medium tracking-wide transition-colors hover:bg-primary/10 hover:text-primary focus:bg-primary/10 focus:text-primary focus:outline-none disabled:pointer-events-none disabled:opacity-50 data-[active]:bg-primary/10 data-[state=open]:bg-primary/10\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <NavigationMenuTriggerPrimitive :disabled="props.disabled" :class="classes">\n    <slot />\n    <svg\n      xmlns="http://www.w3.org/2000/svg"\n      width="16"\n      height="16"\n      viewBox="0 0 24 24"\n      fill="none"\n      stroke="currentColor"\n      stroke-width="2"\n      stroke-linecap="round"\n      stroke-linejoin="round"\n      class="relative top-[1px] ml-1 h-3 w-3 transition duration-200 group-data-[state=open]:rotate-180"\n      aria-hidden="true"\n    >\n      <polyline points="6 9 12 15 18 9" />\n    </svg>\n  </NavigationMenuTriggerPrimitive>\n</template>\n',
    'NavigationMenuViewport.vue':
      '<script setup lang="ts">\nimport type { NavigationMenuViewportProps } from \'./navigation-menu.types\'\nimport { NavigationMenuViewport as NavigationMenuViewportPrimitive } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<NavigationMenuViewportProps>(), {})\n\nconst classes = computed(() =>\n  cn(\n    \'origin-top-center relative mt-1.5 h-[var(--radix-navigation-menu-viewport-height)] w-full overflow-hidden rounded-lg border border-slate-150 bg-white text-popover-foreground shadow-soft font-inter dark:border-navy-500 dark:bg-navy-700 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-90 md:w-[var(--radix-navigation-menu-viewport-width)]\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <div class="absolute left-0 top-full flex justify-center">\n    <NavigationMenuViewportPrimitive :class="classes" />\n  </div>\n</template>\n',
    'index.ts':
      'export type {\n  NavigationMenuContentProps,\n  NavigationMenuIndicatorProps,\n  NavigationMenuItemProps,\n  NavigationMenuLinkProps,\n  NavigationMenuListProps,\n  NavigationMenuProps,\n  NavigationMenuTriggerProps,\n  NavigationMenuViewportProps,\n} from \'./navigation-menu.types\'\nexport { default as NavigationMenu } from \'./NavigationMenu.vue\'\nexport { default as NavigationMenuContent } from \'./NavigationMenuContent.vue\'\nexport { default as NavigationMenuIndicator } from \'./NavigationMenuIndicator.vue\'\nexport { default as NavigationMenuItem } from \'./NavigationMenuItem.vue\'\nexport { default as NavigationMenuLink } from \'./NavigationMenuLink.vue\'\nexport { default as NavigationMenuList } from \'./NavigationMenuList.vue\'\nexport { default as NavigationMenuTrigger } from \'./NavigationMenuTrigger.vue\'\nexport { default as NavigationMenuViewport } from \'./NavigationMenuViewport.vue\'\n',
    'navigation-menu.types.ts':
      'import type { HTMLAttributes } from \'vue\'\n\nexport interface NavigationMenuProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuListProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuItemProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuTriggerProps {\n  /**\n   * When true, prevents the user from interacting with the trigger.\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuContentProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuLinkProps {\n  /**\n   * Whether this link is the currently active page link.\n   * @default false\n   */\n  active?: boolean\n\n  /** The URL the link points to */\n  href?: string\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuViewportProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface NavigationMenuIndicatorProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n',
