    'index.ts':
      'export { default as EditorContent } from \'./EditorContent.vue\'\nexport { default as EditorToolbar } from \'./EditorToolbar.vue\'\nexport type {\n  EditorContentProps,\n  EditorToolbarProps,\n  RichTextEditorProps,\n  ToolbarButtonProps,\n  ToolbarGroupProps,\n  ToolbarItem,\n  ToolbarItemCommand,\n  ToolbarSeparatorProps,\n} from \'./rich-text-editor.types\'\nexport { DEFAULT_TOOLBAR } from \'./rich-text-editor.types\'\nexport { default as RichTextEditor } from \'./RichTextEditor.vue\'\nexport { default as ToolbarButton } from \'./ToolbarButton.vue\'\nexport { default as ToolbarGroup } from \'./ToolbarGroup.vue\'\nexport { default as ToolbarSeparator } from \'./ToolbarSeparator.vue\'\n',
    'rich-text-editor.types.ts':
      'import type { Editor } from \'@tiptap/vue-3\'\nimport type { HTMLAttributes } from \'vue\'\n\n/** A toolbar item can be a command name, \'separator\', or a group of commands */\nexport type ToolbarItemCommand =\n  | \'bold\'\n  | \'italic\'\n  | \'underline\'\n  | \'strikethrough\'\n  | \'heading1\'\n  | \'heading2\'\n  | \'heading3\'\n  | \'bulletList\'\n  | \'orderedList\'\n  | \'blockquote\'\n  | \'codeBlock\'\n  | \'link\'\n  | \'image\'\n  | \'undo\'\n  | \'redo\'\n\nexport type ToolbarItem = ToolbarItemCommand | \'separator\' | ToolbarItemCommand[]\n\nexport const DEFAULT_TOOLBAR: ToolbarItem[] = [\n  [\'bold\', \'italic\', \'underline\', \'strikethrough\'],\n  \'separator\',\n  [\'heading1\', \'heading2\', \'heading3\'],\n  \'separator\',\n  [\'bulletList\', \'orderedList\'],\n  \'separator\',\n  [\'blockquote\', \'codeBlock\'],\n  \'separator\',\n  [\'link\', \'image\'],\n  \'separator\',\n  [\'undo\', \'redo\'],\n]\n\nexport interface RichTextEditorProps {\n  /** HTML string content (v-model) */\n  modelValue?: string\n\n  /** Placeholder text shown when editor is empty */\n  placeholder?: string\n\n  /**\n   * Whether the editor is disabled\n   * @default false\n   */\n  disabled?: boolean\n\n  /**\n   * Toolbar configuration\n   * @default DEFAULT_TOOLBAR\n   */\n  toolbar?: ToolbarItem[]\n\n  /**\n   * Minimum height of the editor content area\n   * @default \'150px\'\n   */\n  minHeight?: string\n\n  /**\n   * Maximum height of the editor content area\n   * @default \'500px\'\n   */\n  maxHeight?: string\n\n  /**\n   * Maximum character count (0 = unlimited)\n   * @default 0\n   */\n  maxLength?: number\n\n  /**\n   * Whether to show character count\n   * @default false\n   */\n  showCharacterCount?: boolean\n\n  /**\n   * Whether the editor is in an error state\n   * @default false\n   */\n  error?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface EditorToolbarProps {\n  /** The tiptap editor instance */\n  editor: Editor | null\n\n  /** Toolbar items configuration */\n  items?: ToolbarItem[]\n\n  /**\n   * Whether the toolbar is disabled\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ToolbarButtonProps {\n  /** The tiptap editor instance */\n  editor: Editor | null\n\n  /** The toolbar command name */\n  command: ToolbarItemCommand\n\n  /**\n   * Whether the button is disabled\n   * @default false\n   */\n  disabled?: boolean\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ToolbarGroupProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface ToolbarSeparatorProps {\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n\nexport interface EditorContentProps {\n  /** The tiptap editor instance */\n  editor: Editor | null\n\n  /**\n   * Minimum height of the content area\n   * @default \'150px\'\n   */\n  minHeight?: string\n\n  /**\n   * Maximum height of the content area\n   * @default \'500px\'\n   */\n  maxHeight?: string\n\n  /** Additional CSS classes */\n  class?: HTMLAttributes[\'class\']\n}\n',
