      '<script setup lang="ts">\nimport type { SelectProps } from \'./select.types\'\nimport { SelectRoot } from \'radix-vue\'\n\n// eslint-disable-next-line unused-imports/no-unused-vars\nconst props = withDefaults(defineProps<SelectProps>(), {\n  disabled: false,\n  defaultOpen: false,\n})\n\nconst emit = defineEmits<{\n  \'update:modelValue\': [value: string]\n}>()\n</script>\n\n<template>\n  <SelectRoot\n    :model-value="modelValue"\n    :disabled="disabled"\n    :default-open="defaultOpen"\n    @update:model-value="emit(\'update:modelValue\', $event)"\n  >\n    <slot />\n  </SelectRoot>\n</template>\n',
    'SelectContent.vue':
      '<script setup lang="ts">\nimport type { SelectContentProps } from \'./select.types\'\nimport { SelectContent as SelectContentPrimitive, SelectPortal, SelectViewport } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<SelectContentProps>(), {\n  position: \'popper\',\n})\n\nconst classes = computed(() =>\n  cn(\n    \'relative z-50 max-h-96 min-w-[8rem] overflow-hidden rounded-md border border-slate-150 dark:border-navy-500 bg-popover text-popover-foreground font-inter shadow-soft data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95\',\n    props.position === \'popper\'\n    && \'data-[side=bottom]:translate-y-1 data-[side=left]:-translate-x-1 data-[side=right]:translate-x-1 data-[side=top]:-translate-y-1\',\n    props.class,\n  ),\n)\n\nconst viewportClasses = computed(() =>\n  cn(\n    \'p-1\',\n    props.position === \'popper\'\n    && \'h-[var(--radix-select-trigger-height)] w-full min-w-[var(--radix-select-trigger-width)]\',\n  ),\n)\n</script>\n\n<template>\n  <SelectPortal>\n    <SelectContentPrimitive :position="position" :class="classes">\n      <SelectViewport :class="viewportClasses">\n        <slot />\n      </SelectViewport>\n    </SelectContentPrimitive>\n  </SelectPortal>\n</template>\n',
