    'SelectItem.vue':
      '<script setup lang="ts">\nimport type { SelectItemProps } from \'./select.types\'\nimport { SelectItemIndicator, SelectItem as SelectItemPrimitive, SelectItemText } from \'radix-vue\'\nimport { computed } from \'vue\'\nimport { cn } from \'../../utils\'\n\nconst props = withDefaults(defineProps<SelectItemProps>(), {\n  disabled: false,\n})\n\nconst classes = computed(() =>\n  cn(\n    \'relative flex h-8 w-full cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none focus:bg-primary/10 focus:text-primary data-[disabled]:pointer-events-none data-[disabled]:opacity-50\',\n    props.class,\n  ),\n)\n</script>\n\n<template>\n  <SelectItemPrimitive :value="value" :disabled="disabled" :class="classes">\n    <span class="absolute left-2 flex h-3.5 w-3.5 items-center justify-center">\n      <SelectItemIndicator>\n        <svg\n          xmlns="http://www.w3.org/2000/svg"\n          width="16"\n          height="16"\n          viewBox="0 0 24 24"\n          fill="none"\n          stroke="currentColor"\n          stroke-width="2"\n          stroke-linecap="round"\n          stroke-linejoin="round"\n          class="h-4 w-4"\n          aria-hidden="true"\n        >\n          <polyline points="20 6 9 17 4 12" />\n        </svg>\n      </SelectItemIndicator>\n    </span>\n    <SelectItemText>\n      <slot />\n    </SelectItemText>\n  </SelectItemPrimitive>\n</template>\n',
